sql:
SELECT name
FROM assessment_templates
WHERE active = 1 AND department = 'Computer Science';

SELECT name
FROM evaluation_standards
WHERE active = 1;

SELECT AVG(score) AS average_score
FROM presentation_scores
WHERE grading_status = 'Completed';

SELECT COUNT(presentation_id) AS total_presentations
FROM presentations
WHERE student_id = 0;

SELECT DISTINCT p.student_id
FROM presentations p
ORDER BY p.student_id;

external_knowledge:
Active assessments: Assessments that are currently running and accepting submissions; 
Graded presentations: Presentations that have been evaluated and assigned a score by the instructor;
Overall score: The total score of a presentation calculated by summing up the product of the score and weight for each criterion.

sql:
SELECT name
FROM assessments
ORDER BY name;

SELECT MAX(score) AS max_score
FROM presentation_scores
WHERE criterion_id = 0;

SELECT AVG(file_size) AS average_file_size
FROM submission_files
WHERE presentation_id = 1;

SELECT s.name
FROM students s
WHERE s.student_id IN (
  SELECT gm.student_id
  FROM group_members gm
);

SELECT submission_date
FROM presentations
WHERE status = 'Submitted' AND assessment_id = 0;
